// Pull every snapshot the LLM needs in parallel.
const BASE = 'https://n8n.thisaimachine.com/webhook';
const paths = {
  alerts:     '/alerts/pending',
  services:   '/services/health',
  wazuh:      '/wazuh/insights',
  auth:       '/dashboard-auth/summary',
  catalog:    '/actions/catalog',
  suppressed: '/actions/suppressed?days=7'
};

const pairs = await Promise.all(Object.entries(paths).map(async ([k, p]) => {
  try {
    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: BASE + p,
      timeout: 15000,
      ignoreHttpStatusErrors: true,
      json: true
    });
    return [k, Array.isArray(data) ? data[0] : data];
  } catch (e) {
    return [k, { _error: e?.message || String(e) }];
  }
}));

const snap = Object.fromEntries(pairs);
return [{ json: { snap } }];

// Render the snapshot as a structured prompt + build the OpenAI request body.
const snap = $json.snap || {};

function safeArr(v) { return Array.isArray(v) ? v : (v ? [v] : []); }
function trunc(s, n) { return s && s.length > n ? s.slice(0, n - 1) + '…' : s; }

let text = '';

// Active alerts
const alerts = (snap.alerts && snap.alerts.alerts) || [];
text += `## Active alerts (${alerts.length})\n`;
if (alerts.length === 0) text += 'None.\n';
else for (const a of alerts) {
  text += `- [${(a.severity||'?').toUpperCase()}] ${a.title || a.id}`;
  if (a.body) text += ` — ${a.body}`;
  text += `  (id: ${a.id}, fired ${a.fired_at || '?'})\n`;
}
text += '\n';

// Services
const services = (snap.services?.services) || [];
const summary = snap.services?.summary || {};
const down = services.filter(s => s.status === 'down');
const auth = services.filter(s => s.status === 'auth');
const flapping = services.filter(s => s.status === 'up' && s.uptime_24h_pct != null && s.uptime_24h_pct < 99);
text += `## Services (${summary.total || services.length} total, ${summary.up || 0} up, ${summary.down || 0} down, ${summary.auth || 0} auth)\n`;
if (down.length === 0 && flapping.length === 0) text += 'All services healthy.\n';
for (const s of down) text += `- DOWN: ${s.name} — ${s.error || 'no error'} (link: ${s.url})\n`;
for (const s of auth) text += `- AUTH-WALL: ${s.name}\n`;
for (const s of flapping.slice(0, 8)) text += `- FLAPPING: ${s.name}, ${s.uptime_24h_pct}% uptime / 24h (last_down: ${s.last_down_at || '?'})\n`;
text += '\n';

// Wazuh
const waz = snap.wazuh || {};
text += `## Wazuh (last 24h)\n`;
let wazAny = false;
if (waz.failed_auth?.total > 0) {
  wazAny = true;
  text += `- Failed auth: ${waz.failed_auth.total} attempts\n`;
  for (const ip of safeArr(waz.failed_auth.by_ip).slice(0, 5)) {
    text += `  - ${ip.ip}: ${ip.count} attempts (${(ip.agents||[]).join(', ')})\n`;
  }
}
if (waz.high_alerts?.length > 0) {
  wazAny = true;
  text += `- High-severity alerts: ${waz.high_alerts.length}\n`;
  for (const a of waz.high_alerts.slice(0, 5)) text += `  - ${trunc(a.description, 80)} (×${a.count})\n`;
}
if (waz.priv_escalation?.total > 0) {
  wazAny = true;
  text += `- Privilege escalation events: ${waz.priv_escalation.total}\n`;
}
if (waz.vulnerabilities?.length > 0) {
  wazAny = true;
  text += `- Vulnerabilities flagged: ${waz.vulnerabilities.length}\n`;
  for (const v of waz.vulnerabilities.slice(0, 3)) text += `  - ${trunc(v.description, 80)}\n`;
}
if (!wazAny) text += 'Nothing notable.\n';
text += '\n';

// Dashboard auth
const da = snap.auth || {};
const conc = da.concerning?.total || 0;
text += `## Dashboard auth (last ${da.window_days || 7}d)\n`;
const cls = da.classification || {};
text += `- Total credential-less 401s: ${da.total || 0} (${cls.asset_probes || 0} asset probes, ${cls.monitor_probes || 0} monitor probes, ${cls.endpoint_probes || 0} endpoint probes, ${cls.real_attempts || 0} real bad-password)\n`;
text += `- Concerning external IPs: ${conc}\n`;
if (conc > 0) {
  for (const ip of safeArr(da.concerning?.by_ip).slice(0, 5)) {
    text += `  - ${ip.ip}: ${ip.real_attempts || 0} bad-password, ${ip.endpoint_probes || 0} endpoint probes\n`;
  }
}
text += '\n';

// Available actions
const catalog = snap.catalog?.catalog || {};
text += `## Available actions you may recommend\n`;
for (const [id, a] of Object.entries(catalog)) {
  const args = a.args_schema && Object.keys(a.args_schema).length
    ? `(${Object.entries(a.args_schema).map(([k,v]) => `${k}: ${v}`).join(', ')})`
    : '()';
  text += `- ${id}${args}  [risk: ${a.risk}]  — ${a.description}\n`;
  if (a.example_args) text += `  example_args: ${JSON.stringify(a.example_args)}\n`;
}
text += '\n';

// Suppressed
const suppressed = snap.suppressed?.suppressed || [];
if (suppressed.length > 0) {
  text += `## Recently dismissed (do NOT re-recommend these exact (id, args) combinations)\n`;
  for (const s of suppressed) {
    text += `- ${s.action_id} with args ${JSON.stringify(s.args)}\n`;
  }
  text += '\n';
}

const systemPrompt = `You are a helpful homelab analyst writing a daily briefing for the user.

Produce:
1. A summary in markdown (2-4 short paragraphs). Focus on what's NEW or NOTABLE — don't re-state every metric. Lead with anything that needs attention. Be specific (name the alerts, services, IPs, rules involved). If everything is healthy, say so in one sentence and stop.
2. A list of 0-5 recommended actions. If nothing genuinely needs the user's intervention, return an empty array — do NOT pad.

Hard rules for actions:
- ONLY recommend MUTATING actions (those with readonly: false in the catalog). Read-only actions like list_alerts or get_service_history exist for the agent to look things up — they should NOT appear in the briefing because the user is already reading the briefing.
- NEVER recommend an action not in the AVAILABLE ACTIONS list.
- NEVER re-propose any (id, args) pair from the RECENTLY DISMISSED list.
- Each recommendation's 'description' must reference specific entities from this user's data (alert ids, service names, IP addresses) — never generic advice.
- 'args' MUST match the action's args_schema exactly. For ack_alerts, args MUST be {"ids": ["<actual-alert-id-from-active-list>", ...]} drawn from the active alerts; never invent ids.
- Risk MUST match the action's declared risk in the catalog.
- Distinguish dashboard 'Active alerts' (the pending_alerts table — these can be acked via ack_alerts) from Wazuh 'High-severity alerts' (these are observations from the security log; they cannot be acked from this dashboard).

Return STRICT JSON only, no markdown fences:
{
  "summary": "Markdown text here.",
  "actions": [
    { "id": "ack_alerts", "title": "…", "description": "…", "args": {"ids": ["…"]}, "risk": "low" }
  ]
}`;

const requestBody = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: text }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.3,
  max_tokens: 1500
});

return [{ json: { requestBody, snapshotText: text } }];

// Parse the OpenAI completion, validate against the catalog, build SQL.
const raw = $json.choices?.[0]?.message?.content || '';

let parsed = { summary: '', actions: [] };
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    summary: 'AI briefing generation returned invalid JSON. Raw response: ' + raw.slice(0, 600),
    actions: []
  };
}

const snapJson = $('Gather Snapshot').first().json.snap || {};
const catalog = snapJson.catalog?.catalog || {};
const suppressed = snapJson.suppressed?.suppressed || [];
const suppressedKeys = new Set(suppressed.map(s => `${s.action_id}|${s.args_hash}`));

function argsHash(args) {
  const sortedKeys = Object.keys(args || {}).sort();
  const canonical = JSON.stringify(args || {}, sortedKeys);
  let h1 = 5381n, h2 = 7853n, h3 = 9871n, h4 = 11483n;
  const M = 0xffffffffffffffffn;
  for (let i = 0; i < canonical.length; i++) {
    const c = BigInt(canonical.charCodeAt(i));
    h1 = ((h1 << 5n) + h1 + c) & M;
    h2 = ((h2 << 5n) + h2 + c) & M;
    h3 = ((h3 << 5n) + h3 + c) & M;
    h4 = ((h4 << 5n) + h4 + c) & M;
  }
  return [h1, h2, h3, h4].map(h => h.toString(16).padStart(16, '0')).join('');
}

// Validate each action: must be in catalog, not in suppressed, schema OK,
// and pass per-action sanity (e.g. ack_alerts ids must exist in active alerts).
const activeAlertIds = new Set(((snapJson.alerts && snapJson.alerts.alerts) || []).map(a => a.id));

const validated = [];
for (const proposal of (parsed.actions || [])) {
  if (!proposal || typeof proposal !== 'object') continue;
  if (!proposal.id || !catalog[proposal.id]) continue;

  let args = proposal.args || {};

  // Per-action sanity: ack_alerts ids MUST exist in the live active alerts.
  // The LLM tends to hallucinate ids; strip non-existent ones, drop the action
  // if none remain.
  if (proposal.id === 'ack_alerts') {
    const rawIds = Array.isArray(args.ids) ? args.ids : [];
    const realIds = rawIds.filter(id => activeAlertIds.has(id));
    if (realIds.length === 0) continue;
    args = { ids: realIds };
  }

  const hash = argsHash(args);
  if (suppressedKeys.has(`${proposal.id}|${hash}`)) continue;

  validated.push({
    id: proposal.id,
    title: String(proposal.title || proposal.id).slice(0, 200),
    description: String(proposal.description || '').slice(0, 1000),
    args,
    args_hash: hash,
    risk: ['low','medium','high'].includes(proposal.risk) ? proposal.risk : (catalog[proposal.id].risk || 'low')
  });
}

const summaryEsc = String(parsed.summary || '').replace(/\\/g, '\\\\').replace(/'/g, "''");
const actionsEsc = JSON.stringify(validated).replace(/\\/g, '\\\\').replace(/'/g, "''");
const rawEsc = String(raw).replace(/\\/g, '\\\\').replace(/'/g, "''").slice(0, 60000);

const sql = `REPLACE INTO ai_briefings (date, summary_md, actions, raw_response) VALUES (CURDATE(), '${summaryEsc}', '${actionsEsc}', '${rawEsc}')`;

return [{ json: { sql, briefing: { summary_md: parsed.summary || '', actions: validated, generated_at: new Date().toISOString() } } }];

// Combine the briefing row with recent action decisions so each action carries
// its current status (proposed | accepted | dismissed).
const briefingRow = $('Query Latest').first()?.json;
if (!briefingRow || !briefingRow.date) {
  return [{ json: { exists: false } }];
}

const decisions = $input.all().map(i => i.json);
const byKey = new Map();
for (const d of decisions) {
  const k = `${d.action_id}|${d.args_hash}`;
  // Keep the most recent (rows already ORDER BY decided_at DESC).
  if (!byKey.has(k)) byKey.set(k, d);
}

let actions = [];
try {
  const raw = briefingRow.actions;
  actions = typeof raw === 'string' ? JSON.parse(raw) : (raw || []);
} catch {}

const annotated = (actions || []).map(a => {
  const dec = byKey.get(`${a.id}|${a.args_hash}`);
  return {
    ...a,
    status: dec ? dec.decision : 'proposed',
    decided_at: dec ? new Date(Number(dec.decided_at_unix) * 1000).toISOString() : null
  };
});

const createdUnix = Number(briefingRow.created_at_unix) || null;

return [{ json: {
  exists: true,
  date: String(briefingRow.date).slice(0, 10),
  summary_md: briefingRow.summary_md || '',
  actions: annotated,
  dismissed: !!briefingRow.dismissed_at,
  generated_at: createdUnix ? new Date(createdUnix * 1000).toISOString() : null
}}];
